2.8. Executing PROC_DFF pass (convert process syncs to FFs).
Creating register for signal `\ResetController.\rst' using process `\ResetController.$proc$ResetController.v:17$1'.
ERROR: Multiple edge sensitive events found for this signal!
```


Target code (generated by sv2v):
```verilog
module ResetController (
	clk,
	rstTrigger,
	locked,
	rst,
	rstStart
);
	parameter CYCLE_OF_RESET_SEQUENCE = 10000;
	input wire clk;
	input wire rstTrigger;
	input wire locked;
	output reg rst;
	output reg rstStart;
	reg [$clog2(CYCLE_OF_RESET_SEQUENCE):0] count;
	localparam BasicTypes_FALSE = 1'b0;
	localparam BasicTypes_TRUE = 1'b1;
	always @(posedge clk or posedge rstTrigger)
		if (rstTrigger || !locked) begin
			count <= 0;
			rst <= BasicTypes_TRUE;
		end
		else if (rst) begin
			count <= count + 1;
			rst <= (count >= CYCLE_OF_RESET_SEQUENCE ? BasicTypes_FALSE : BasicTypes_TRUE);
		end
		else begin
			count <= 0;
			rst <= BasicTypes_FALSE;
		end
	always @(*) rstStart = (rst && (count == 0) ? BasicTypes_TRUE : BasicTypes_FALSE);
endmodule
```

Original target code (https://github.com/rsd-devel/rsd/blob/8777d59e0b9aa06e4df06711d00754a2f8a51d8b/Processor/Src/ResetController.sv#L7-L44):
```verilog
module ResetController #(
    parameter CYCLE_OF_RESET_SEQUENCE = 10000
)(
    input  logic clk, rstTrigger, locked,
    output logic rst, rstStart
);
    logic unsigned [ $clog2(CYCLE_OF_RESET_SEQUENCE):0 ] count;
    
    always_ff @(posedge clk or posedge rstTrigger) begin
        if ( rstTrigger || !locked ) begin
            count <= 0;
            rst <= TRUE;
        end
        else if ( rst ) begin
            count <= count + 1;
            rst <= ( count >= CYCLE_OF_RESET_SEQUENCE ? FALSE : TRUE );
        end
        else begin
            count <= 0;
            rst <= FALSE;
        end
    end

    always_comb begin
        rstStart = ( rst && count == 0 ) ? TRUE : FALSE;
    end
endmodule
```

